/*View in dark mode for good effects*/
.darma-loader-uiverse-crimson-halo-ring {
  border: 4px solid red;
  width: 100px;
  height: 100px;
  border-radius: 50%;
  border-right-color: transparent;
  animation: darma-loader-uiverse-crimson-halo-ring-rot 1s linear infinite;
  box-shadow: 0px 0px 20px red inset;
}

@keyframes darma-loader-uiverse-crimson-halo-ring-rot {
100% {
transform: rotate(360deg);
}
}

